public class EthereumBlockVerifier {
 public static boolean verifyBlock(EthereumBlock block) {
 // Verify the block's state root
 String stateRoot = block.getHeader().getStateRoot();
 String calculatedStateRoot = calculateStateRoot(block);
 if (!stateRoot.equals(calculatedStateRoot)) {
 return false;
 }

 // Verify the block's transactions root
 String transactionsRoot = block.getHeader().getTransactionsRoot();
 String calculatedTransactionsRoot = calculateTransactionsRoot(block);
 if (!transactionsRoot.equals(calculatedTransactionsRoot)) {
 return false;
 }

 // Verify the block's receipts root
 String receiptsRoot = block.getHeader().getReceiptsRoot();
 String calculatedReceiptsRoot = calculateReceiptsRoot(block);
 if (!receiptsRoot.equals(calculatedReceiptsRoot)) {
 return false;
 }

 return true;
 }

